requests.preRequestScript:
insomnia.baseGlobals.set('globalBaseWrite', 'base');
insomnia.globals.set('globalSelectedWrite', 'selected');
insomnia.baseEnvironment.set('collectionBaseWrite', 'base');
insomnia.environment.set('collectionSelectedWrite', 'selected');
insomnia.request.addHeader({ name: 'X-Brunomnia-CLI', value: 'true' });
insomnia.request.body.update({ mode: 'file', file: 'examples/cli-script-file.txt' });

requests.tests:
insomnia.test('Status and scopes are exact', async () => { await Promise.resolve(); insomnia.expect(insomnia.response.status).to.be.oneOf([200, 204]); insomnia.expect(insomnia.baseGlobals.get('globalBaseWrite')).to.equal('base'); insomnia.expect(insomnia.globals.get('globalSelectedWrite')).to.equal('selected'); insomnia.expect(insomnia.baseEnvironment.get('collectionBaseWrite')).to.equal('base'); insomnia.expect(insomnia.environment.get('collectionSelectedWrite')).to.equal('selected'); });
insomnia.test('Body is JSON', () => { insomnia.expect(insomnia.response.json()).to.be.an('object').that.has.all.keys('ok'); });
insomnia.test('Bundled modules share the desktop contract', () => { const Ajv = require('ajv'); const digest = require('crypto-js').SHA256('abc').toString(); const rows = require('csv-parse').sync('id,name\n1,Ada', { columns: true }); const assert = require('chai').assert; assert.deepNestedPropertyVal({ response: { body: rows[0] } }, 'response.body', { id: '1', name: 'Ada' }); assert.containsAllKeys(rows[0], ['id', 'name']); insomnia.expect(new Ajv().validate({ required: ['id'] }, rows[0])).to.be.true; insomnia.expect(digest).to.equal('ba7816bf8f01cfea414140de5dae2223b00361a396177a9cb410ff61f20015ad'); });
insomnia.test('Local file attachment is explicit', () => { insomnia.expect(insomnia.request.binaryBody.fileName).to.equal('cli-script-file.txt'); insomnia.expect(require('buffer').Buffer.from(insomnia.request.binaryBody.dataBase64, 'base64').toString()).to.equal('Brunomnia script file fixture\n'); });
